import psycopg2

def search_users(username, email, role, status):
    conn = psycopg2.connect(database="mydatabase")
    cur = conn.cursor()
    
    # Build the SQL query based on the input parameters
    query = "SELECT * FROM users"
    if username:
        query += " WHERE username = %s"
    if email:
        query += " AND email = %s"
    if role:
        query += " AND role = %s"
    if status:
        query += " AND status = %s"
    
    # Execute the SQL query and fetch the results
    cur.execute(query, (username, email, role, status))
    rows = cur.fetchall()
    
    # Close the cursor and connection
    cur.close()
    conn.close()
    
    return rows